VALUES
  ('elementary-7fec267e-moex-00414', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '由於網路交友盛行，某甲盜用某乙的照片當作自己交友網站上的大頭貼，被乙的友人發現後轉知乙。乙 獲知自己的照片被盜用後，決定捍衛自己的肖像權。下列何者不能作為乙解決與甲糾紛的途徑？', '["乙透過臉書聯絡甲於媽祖廟和解，兩人私下協議並作成和解契約", "乙對甲提告，雙方可在第一審訴訟進行中，合意向法院聲請調解", "乙與甲可在訴訟外達成民事和解", "若甲不履行訴訟外和解契約的內容，乙可逕行向法院聲請強制執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00415', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '汽車駕駛人違規停車，依道路交通管理處罰條例遭裁罰新臺幣1,000元，該裁罰之法律上性質應屬下 列何者？', '["行政罰", "特別刑罰", "促其履行義務之怠金", "特別公課"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00416', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '憲法第53條明定行政院為國家最高行政機關，使所有國家之行政事務，均納入以行政院為金字塔頂端之 層級式行政體制掌理，經由層級節制，最終並均歸行政院之指揮監督。該條規定之主要目的，在於維護 下列何種原則？', '["法律保留原則", "行政一體原則", "法律優越原則", "代議民主原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00417', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '關於限制人身自由的各類處分，下列何者依現行法制無須由法院為之？', '["社會秩序維護法所規定之拘留", "刑事訴訟法所規定之羈押", "行政執行法所規定之管收", "傳染病防治法所規定之強制隔離"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00418', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '依國家賠償法規定，受害人民請求損害賠償時，應先行下列何種程序？', '["應先向賠償義務機關之上級機關提出賠償申請", "應先向行政法院提起訴訟確認賠償責任歸屬", "應先以書面向賠償義務機關請求並與其協議", "應先向監察院舉報立案並提供相關具體事證"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00419', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '人民因行政機關對其依法申請之案件予以駁回，而認為其權利受到違法損害者，經訴願程序未獲救濟， 此時依行政訴訟法之規定，應提起下列何種類型之訴訟，以請求作成特定內容之行政處分？', '["課予義務訴訟", "撤銷訴訟", "一般給付訴訟", "確認行政處分違法訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00420', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '參加國家考試的阿明對於考試信心滿滿，收到考試成績單後，居然落榜！他決定提起救濟。關於阿明行 政救濟的程序，下列何者正確？', '["阿明對於成績有疑義要向辦理國家考試的考試院提申訴", "若不服訴願結果，可向地方法院行政訴訟庭提起第一審訴訟", "若阿明不服第一審訴訟結果，還可以上訴到最高行政法院", "若最高行政法院判決敗訴，阿明可以透過非常上訴尋求救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00421', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '世界上多數國家從1960年代起，陸續將投票年齡從21歲下修至18歲，因應世界潮流，我國朝野也有投 票權年齡下修的共識。依據憲法增修條文規定，有關修法的程序，下列敘述何者正確？', '["人民連署提案後，逕由公民投票決定", "行政院院會提案，交由立法院表決通過", "立法院提案表決通過後，由公民複決", "立法院提案表決後，交憲法法庭審理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00422', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '我國以憲法為基礎，發展法律分類而組成法律體系，下列敘述何者正確？', '["法律位階較憲法低，有牴觸憲法疑慮時，由大法官提出聲請並解釋", "以「條例、通則」為名稱者，須經中央立法機關三讀程序制定", "行政機關發布的行政命令不具強制性，僅為人民遵循國家統治的參考", "依據法規範體系，法位階層級越高，效力越強，規定必須越明確詳盡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00423', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '過去未成年人觸法可能送往少年法院，2019 年《少年事件處理法》修法後，面對觸法之未成年者將由教 育、社政等機關優先輔導之。《少年事件處理法》修法之目的可與下列那一概念相呼應？', '["刑罰謙抑原則", "無罪推定原則", "偵查不公開原則", "禁止類推適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
